sql:
SELECT COUNT(DISTINCT p.module_id)
FROM providers p
WHERE p.provider_type = 'Service';

WITH RoutedModuleID AS (
    SELECT module_id FROM modules WHERE module_name = 'Routed'
)
SELECT m.module_name
FROM modules m
INNER JOIN imports i ON m.module_id = i.module_id
WHERE i.imported_module_id = (SELECT module_id FROM RoutedModuleID)
AND m.module_id IN (
    SELECT module_id FROM exports WHERE exported_component = 'User Service'
);

external_knowledge:
; Module details refer to information about the modules, including their unique identifiers, names, and versions; 
; Exported components refer to the components or modules that are made available by the modules; 
; Provider types refer to the categories of providers, such as services or guards; 
; Access levels refer to the levels of access, such as read, write, or deploy, assigned to users for the modules.

sql:
SELECT m.module_name, mv.version 
FROM modules m
JOIN module_versions mv ON m.module_id = mv.module_id;

SELECT m.module_id, m.module_name, mv.version
FROM modules m
LEFT JOIN module_versions mv ON m.module_id = mv.module_id;

SELECT access_level, COUNT(user_id) AS user_count
FROM access_rights
GROUP BY access_level;

SELECT module_id, module_name, updated_at
FROM modules
ORDER BY updated_at DESC;
